function solve(nums: number[]): number {
    let maxSum = -Infinity;
    const n = nums.length;

    for (let l = 0; l < n - 3; l++) {
        // Find p such that nums[l...p] is strictly increasing
        let p = l;
        while (p + 1 < n && nums[p] < nums[p + 1]) {
            p++;
        }

        // Find q such that nums[p...q] is strictly decreasing
        let q = p;
        while (q + 1 < n && nums[q] > nums[q + 1]) {
            q++;
        }

        // Find r such that nums[q...r] is strictly increasing
        let r = q;
        while (r + 1 < n && nums[r] < nums[r + 1]) {
            r++;
        }

        // Check if the subarray is valid (l < p < q < r)
        if (l < p && p < q && q < r) {
            const currentSum = nums.slice(l, r + 1).reduce((a, b) => a + b, 0);
            maxSum = Math.max(maxSum, currentSum);
